type=\"radio\" name=\"format\" value=\"excel\">\n								<span><i class='bx bxs-file-spreadsheet'></i> Excel</span>\n							</label>\n							<label class=\"format-option\">\n								<input type=\"radio\" name=\"format\" value=\"csv\">\n								<span><i class='bx bxs-file-css'></i> CSV</span>\n							</label>\n						</div>\n					</div>\n					<button class=\"generate-btn\" onclick=\"generateReport()\">\n						<i class='bx bx-cog'></i>\n						Generate Report\n					</button>\n				</div>\n			</div>\n		</main>\n		<!-- MAIN -->\n	</section>\n	<!-- CONTENT -->\n	\n\n	<script src=\"../js/auth.js\"></script>\n	<script src=\"script.js\"></script>\n	<script>\n		// Download functionality\n		function downloadFile(filename) {\n			// Simulate download\n			const btn = event.currentTarget;\n			btn.innerHTML = '<i class=\"bx bx-loader-alt bx-spin\"></i> Downloading...';\n			btn.classList.add('downloading');\n			\n			setTimeout(() => {\n				btn.innerHTML = '<i class=\"bx bx-check\"></i> Downloaded';\n				btn.classList.remove('downloading');\n				btn.classList.add('downloaded');\n				\n				// Update download count\n				const countEl = btn.previousElementSibling;\n				if (countEl) {\n					const currentCount = parseInt(countEl.textContent);\n					countEl.innerHTML = `<i class='bx bx-download'></i> ${currentCount + 1}`;\n				}\n				\n				setTimeout(() => {\n					btn.innerHTML = '<i class=\"bx bx-download\"></i> Download';\n					btn.classList.remove('downloaded');\n				}, 2000);\n			}, 1500);\n		}\n\n		// Generate new report\n		function generateReport() {\n			const reportType = document.getElementById('reportType').value;\n			const startDate = document.getElementById('startDate').value;\n			const endDate = document.getElementById('endDate').value;\n			const format = document.querySelector('input[name=\"format\"]:checked').value;\n			\n			if (!reportType) {\n				alert('Please select a report type');\n				return;\n			}\n			\n			if (!startDate || !endDate) {\n				alert('Please select a date range');\n				return;\n			}\n			\n			const btn = document.querySelector('.generate-btn');\n			btn.innerHTML = '<i class=\"bx bx-loader-alt bx-spin\"></i> Generating...';\n			btn.disabled = true;\n			\n			setTimeout(() => {\n				btn.innerHTML = '<i class=\"bx bx-check\"></i> Report Generated!';\n				btn.disabled = false;\n				\n				setTimeout(() => {\n					btn.innerHTML = '<i class=\"bx bx-cog\"></i> Generate Report';\n				}, 2000);\n				\n				alert(`Your ${reportType} report has been generated and is ready for download in ${format.toUpperCase()} format.`);\n			}, 2000);\n		}\n\n		// Filter functionality\n		const filterBtns = document.querySelectorAll('.filter-btn');\n		filterBtns.forEach(btn => {\n			btn.addEventListener('click', () => {\n				filterBtns.forEach(b => b.classList.remove('active'));\n				btn.classList.add('active');\n				\n				const filter = btn.dataset.filter;\n				const downloadItems = document.querySelectorAll('.download-item');\n				\n				downloadItems.forEach(item => {\n					if (filter === 'all' || item.dataset.type === filter) {\n						item.style.display = 'flex';\n					} else {\n						item.style.display = 'none';\n					}\n				});\n			});\n		});\n\n		// Set default dates\n		const today = new Date();\n		const lastMonth = new Date();\n		lastMonth.setMonth(lastMonth.getMonth() - 1);\n		\n		document.getElementById('endDate').valueAsDate = today;\n		document.getElementById('startDate').valueAsDate = lastMonth;\n	</script>\n</body>\n</html>\n\n<?php /* End Admin Downloads */ ?>
